```typescript:services/geminiService.ts
import { GoogleGenAI, Type } from "@google/genai";
import { Product, StockMovement, ParsedNFe } from '../types';

// Helper to safely get the AI client
const getAiClient = () => {
  let apiKey: string | undefined;

  try {
    // Attempt to access process.env.API_KEY.
    // In many build environments (Vite, Webpack), this string is replaced by the actual key at build time.
    // However, if it's NOT replaced and runs in a browser, accessing 'process' throws a ReferenceError.
    // We wrap it in a try-catch to safely handle the "process is not defined" case.
    apiKey = process.env.API_KEY;
  } catch (e) {
    // Ignore ReferenceError (process is not defined). 
    // If we are here, it means the bundler didn't replace the variable and we are in a browser environment without a process polyfill.
    console.debug("process.env.API_KEY access failed (process not defined).");
  }

  if (!apiKey) {
    console.warn("API_KEY is missing or empty. Please check your environment configuration.");
    return null;
  }

  try {
    return new GoogleGenAI({ apiKey });
  } catch (error) {
    console.error("Error initializing GoogleGenAI client:", error);
    return null;
  }
};

