## services/geminiService.ts

Adicionado suporte para leitura de variáveis de ambiente via `import.meta.env` (padrão Vite) como fallback, garantindo que a API Key seja encontrada mesmo se `process.env` não estiver definido pelo bundler.

```typescript:services/geminiService.ts
import { GoogleGenAI, Type } from "@google/genai";
import { Product, StockMovement, ParsedNFe } from '../types';

// Helper to safely get the AI client
const getAiClient = () => {
  let apiKey: string | undefined;

  // 1. Try process.env (Standard requirement)
  try {
    apiKey = process.env.API_KEY;
  } catch (e) {
    // Ignore ReferenceError if process is not defined
  }

  // 2. Try import.meta.env (Vite standard fallback)
  if (!apiKey) {
    try {
       // Cast to any to avoid TypeScript errors if types aren't set up for Vite
       const env = (import.meta as any).env;
       // Check for VITE_API_KEY (standard) or just API_KEY
       apiKey = env?.VITE_API_KEY || env?.API_KEY;
    } catch (e) {
       // Ignore
    }
  }

  if (!apiKey) {
    console.warn("API_KEY is missing. Please set VITE_API_KEY in your .env file.");
    return null;
  }

  try {
    return new GoogleGenAI({ apiKey });
  } catch (error) {
    console.error("Error initializing GoogleGenAI client:", error);
    return null;
  }
};

export const getStockAnalysis = async (
  prompt: string,
  products: Product[],
  movements: StockMovement[]
): Promise<string> => {
  const ai = getAiClient();
  if (!ai) {
    return "Erro de Configuração: A chave de API do Gemini não foi encontrada. Crie um arquivo .env na raiz do projeto e adicione 'VITE_API_KEY=sua_chave'.";
  }

  const model = 'gemini-2.5-flash';

  const systemInstruction = `Você é um assistente especialista em análise de estoque para uma oficina ou pequena indústria. Sua tarefa é analisar os dados de estoque e movimentações em formato JSON e responder à pergunta do usuário de forma clara, concisa e em português.
  - Dados de Produtos: Lista de produtos com ID, nome, quantidade atual, preço unitário e estoque mínimo.
  - Dados de Movimentações: Histórico de entradas e saídas.
  - Para perguntas de previsão (ex: "quando o produto X vai acabar?"), analise o histórico de saídas ('out') para calcular um consumo médio diário ou mensal e faça uma projeção. Deixe claro que é uma estimativa.
  - Para sugestões de compra, considere o estoque atual, o estoque mínimo e o histórico de consumo para recomendar produtos e quantidades a serem comprados.
  - Forneça insights úteis, diretos e baseados nos dados fornecidos.`;

  // Simplify data to reduce token usage and prevent payload errors (XHR errors on large payloads)
  // Limit to top 50 products and last 20 movements
  const simplifiedProducts = products.slice(0, 50).map(p => ({
      name: p.name,
      qty: p.quantity,
      price: p.unit_price,
      min: p.min_stock
  }));

  const simplifiedMovements = movements
    .filter(m => new Date(m.date) > new Date(Date.now() - 90 * 24 * 60 * 60 * 1000))
    .slice(0, 20)
    .map(m => ({
        prod: m.product_name,
        type: m.type,
        qty: m.quantity,
        date: m.date ? m.date.split('T')[0] : 'N/A'
    }));

  const fullPrompt = `
    Aqui estão os dados atuais do estoque (resumidos):
    Produtos (Amostra):
    ${JSON.stringify(simplifiedProducts)}

    Movimentações de Estoque (Recentes):
    ${JSON.stringify(simplifiedMovements)}

    Pergunta do Usuário: "${prompt}"

    Sua análise:
  `;

  try {
    const response = await ai.models.generateContent({
      model: model,
      contents: [{ parts: [{ text: fullPrompt }] }],
      config: {
          systemInstruction: systemInstruction,
          temperature: 0.5,
      }
    });

    if (!response || !response.text) {
        return "A IA processou a solicitação mas não retornou texto. Tente reformular a pergunta.";
    }

    return response.text;
  } catch (error: any) {
    console.error("Error calling Gemini API:", error);
    let errorMessage = error.message || String(error);

    // Handle generic XHR errors common in browsers (AdBlock, Network, Payload too large)
    if (errorMessage.includes("xhr error") || errorMessage.includes("error code: 6")) {
        errorMessage = "Erro de conexão (XHR). O navegador bloqueou a requisição ou a carga de dados é muito grande. Verifique se há bloqueadores de anúncios ativos ou tente com menos dados.";
    } else if (errorMessage.includes("500")) {
        errorMessage = "Erro interno do servidor Google (500). Tente novamente em instantes.";
    } else if (errorMessage.includes("400")) {
        errorMessage = "Chave de API inválida ou solicitação malformada.";
    }

    return `Erro ao consultar IA: ${errorMessage}`;
  }
};

export const parseInvoicePDF = async (pdfBase64: string): Promise<ParsedNFe> => {
    const ai = getAiClient();
    if (!ai) {
        throw new Error("A chave de API do Gemini não está configurada.");
    }

    const model = 'gemini-2.5-flash';

    const prompt = "Analise a nota fiscal ou cupom fiscal em PDF anexado e extraia as informações do fornecedor (emitente) e a lista completa de produtos. Retorne os dados estritamente no formato JSON especificado. Para cada produto, use 'cProd' como código, 'xProd' como nome, 'qCom' como quantidade e 'vUnCom' como preço unitário. Para o fornecedor, use 'xNome' como nome e 'CNPJ' como CNPJ.";

    const pdfPart = {
        inlineData: {
            mimeType: 'application/pdf',
            data: pdfBase64,
        },
    };

    const schema = {
        type: Type.OBJECT,
        properties: {
            supplier: {
                type: Type.OBJECT,
                properties: {
                    name: { type: Type.STRING, description: "Nome do fornecedor (emitente)" },
                    cnpj: { type: Type.STRING, description: "CNPJ do fornecedor (emitente)" },
                },
                required: ['name', 'cnpj']
            },
            products: {
                type: Type.ARRAY,
                items: {
                    type: Type.OBJECT,
                    properties: {
                        code: { type: Type.STRING, description: "Código do produto (cProd)" },
                        name: { type: Type.STRING, description: "Nome/descrição do produto (xProd)" },
                        quantity: { type: Type.NUMBER, description: "Quantidade comercial (qCom)" },
                        unitPrice: { type: Type.NUMBER, description: "Valor unitário comercial (vUnCom)" },
                    },
                    required: ['code', 'name', 'quantity', 'unitPrice']
                },
            },
        },
        required: ['supplier', 'products']
    };

    try {
        const response = await ai.models.generateContent({
            model: model,
            contents: { parts: [{ text: prompt }, pdfPart] },
            config: {
                responseMimeType: "application/json",
                responseSchema: schema,
            },
        });

        if (!response || !response.text) throw new Error("A IA retornou uma resposta vazia.");

        const parsedJson = JSON.parse(response.text);
        return parsedJson as ParsedNFe;

    } catch (error: any) {
        console.error("Error calling Gemini API for PDF parsing:", error);
        if (error.message?.includes('json')) {
            throw new Error("A IA retornou uma resposta em formato inválido. Tente novamente ou verifique o PDF.");
        }
        let errorMessage = error.message || String(error);
        if (errorMessage.includes("xhr error") || errorMessage.includes("error code: 6")) {
             throw new Error("Erro de conexão (XHR) ao enviar PDF. Verifique bloqueadores de anúncios ou tamanho do arquivo.");
        }
        throw new Error(`Erro ao analisar PDF: ${errorMessage}`);
    }
};
